30.4 ALTER TABLE
O comando ALTER TABLE modifica a estrutura de uma tabela já existente:
-- Adicionar uma nova coluna
ALTER TABLE professor ADD COLUMN email VARCHAR(100);

-- Remover uma coluna
ALTER TABLE professor DROP COLUMN email;

-- Alterar o tipo de uma coluna (sintaxe varia por SGBD)
ALTER TABLE professor ALTER COLUMN salario TYPE NUMERIC(10, 2);

-- Adicionar uma restrição
ALTER TABLE aluno ADD CONSTRAINT chk_carga CHECK (carga_total &gt;= 0);
